from PyQt5 import QtCore, QtGui
import base64

def iconFromBase64(base64):
    pixmap = QtGui.QPixmap()
    pixmap.loadFromData(QtCore.QByteArray.fromBase64(base64))
    icon = QtGui.QIcon(pixmap)
    return icon

def PixmapFromBase64(self, base64):
    pixmap = QtGui.QPixmap()
    pixmap.loadFromData(QtCore.QByteArray.fromBase64(base64))
    return pixmap

def Base64FromIcon():
    with open("icon.ico", "rb") as image_file:
        data = base64.b64encode(image_file.read())
        print(data)

def CoolBase64FromIcon():
    try:
        with open("Airport_City_Logo_Ausschnitt.ico", "rb") as image_file:
            # Encode and decode to utf-8 string
            encoded_string = base64.b64encode(image_file.read()).decode('utf-8')
            
            # Split into chunks of 150 characters
            chunk_size = 150
            chunks = [encoded_string[i:i + chunk_size] for i in range(0, len(encoded_string), chunk_size)]
            
            # Join chunks with newlines
            formatted_data = "\n".join(chunks)
            
            # Write to a text file
            with open("icon_base64.txt", "w") as text_file:
                text_file.write(formatted_data)
                
        print("Successfully written to icon_base64.txt")
        
    except FileNotFoundError:
        print("Error: icon.ico not found.")

